use std::path::PathBuf;

use anyhow::{Context as _, Result};
use clap::{Parser, Subcommand};
use serde_json::json;
use smedja_plugins::SkillRegistry;
use smedja_rpc::client::Client;

const AGENTS_TOML_TEMPLATE: &str = r#"# .smedja/agents.toml — workspace agent configuration
# Generated by `smj workspace agents init`

[roles.impl]
description = "Implementation role"
bash = ["read", "write"]

[roles.review]
description = "Review role (read-only bash)"
bash = ["read"]

[roles.test]
description = "Test role"
bash = ["read", "write"]
"#;

#[derive(Parser)]
#[command(name = "smj", about = "smedja control CLI")]
struct Cli {
    /// smdjad socket path (overrides `XDG_RUNTIME_DIR`)
    #[arg(long, env = "SMEDJA_SOCK", global = true)]
    sock: Option<PathBuf>,

    #[command(subcommand)]
    command: Cmd,
}

#[derive(Subcommand)]
enum Cmd {
    /// Daemon lifecycle
    Daemon {
        #[command(subcommand)]
        action: DaemonCmd,
    },
    /// Session management
    Session {
        #[command(subcommand)]
        action: SessionCmd,
    },
    /// Workspace tools
    Workspace {
        #[command(subcommand)]
        action: WorkspaceCmd,
    },
    /// Audit log queries
    Audit {
        #[arg(long)]
        session: Option<String>,
        #[arg(long)]
        since: Option<String>,
    },
    /// Cost ledger
    Cost {
        #[arg(long)]
        session: Option<String>,
        #[arg(long)]
        since: Option<String>,
    },
    /// Manage Claude Code skill files
    Skill {
        #[command(subcommand)]
        action: SkillCmd,
    },
    /// Project task management
    Task {
        #[command(subcommand)]
        action: TaskCmd,
    },
    /// Loop engine control
    Loop {
        #[command(subcommand)]
        action: LoopCmd,
    },
    /// MCP server registry
    Mcp {
        #[command(subcommand)]
        action: McpCmd,
    },
    /// Docker sandbox management
    Sandbox {
        #[command(subcommand)]
        action: SandboxCmd,
    },
    /// Manage model pricing
    Prices {
        #[command(subcommand)]
        action: PricesCmd,
    },
}

#[derive(Subcommand)]
enum DaemonCmd {
    /// Start smdjad in the background
    Start,
    /// Stop a running smdjad
    Stop,
    /// Restart smdjad
    Restart,
    /// Check whether smdjad is running
    Status,
}

#[derive(Subcommand)]
enum SessionCmd {
    List,
    Show {
        id: String,
    },
    Fork {
        id: String,
        #[arg(long)]
        turn: Option<u32>,
    },
    Rollback {
        id: String,
        turn: u32,
    },
    /// List stored blocks for a session
    Blocks {
        id: String,
    },
    /// List checkpoints for a session
    Checkpoint {
        id: String,
    },
    /// Export session cost lineage to JSON
    Export {
        /// Session ID to export
        id: String,
    },
}

#[derive(Subcommand)]
enum WorkspaceCmd {
    /// Agent management
    Agents {
        #[command(subcommand)]
        action: AgentsCmd,
    },
    Index,
}

#[derive(Subcommand)]
enum AgentsCmd {
    /// Print the resolved role→runner→tier→model table for the current workspace
    Show,
    /// Generate a starter .smedja/agents.toml in the current directory
    Init,
}

#[derive(Subcommand)]
enum PricesCmd {
    /// Update prices.toml from a local file or print current prices
    Update {
        /// Path to replacement prices.toml
        #[arg(long)]
        file: Option<std::path::PathBuf>,
    },
}

#[derive(Subcommand)]
enum SkillCmd {
    /// List installed skills
    List,
    /// Install a skill from a SKILL.md file or directory
    Install {
        /// Path to a SKILL.md file or a directory containing one
        path: PathBuf,
    },
    /// Update an existing skill from a SKILL.md file or directory
    Update {
        /// Skill name to update
        name: String,
        /// Path to the new SKILL.md file or a directory containing one
        path: PathBuf,
    },
    /// Remove an installed skill
    Remove {
        /// Skill name to remove
        name: String,
    },
    /// Sync all skills from a bundle directory using symlinks
    Sync {
        /// Path to a directory of skills (e.g. agent-toolkit-bundle/skills)
        path: PathBuf,
    },
}

#[derive(Subcommand)]
enum TaskCmd {
    /// List tasks (optionally filtered by status)
    List {
        #[arg(long)]
        status: Option<String>,
    },
    /// Show details of a specific task
    Show { id: String },
    /// Create a new project task
    Create {
        title: String,
        #[arg(long)]
        description: Option<String>,
    },
    /// Mark a task complete
    Close { id: String },
    /// Start a parallel task across multiple agent roles
    Parallel {
        /// Goal description passed to all roles
        goal: String,
        /// Comma-separated roles: impl,test,review
        #[arg(long, value_delimiter = ',')]
        roles: Vec<String>,
    },
    /// Show per-role status of a parallel task
    Status {
        /// Parallel task ID returned by `smj task parallel`
        id: String,
    },
    /// Cancel a running parallel task
    Cancel {
        /// Parallel task ID to cancel
        id: String,
    },
}

#[derive(Subcommand)]
enum LoopCmd {
    /// Run a loop against an `OpenSpec` change
    Run {
        /// Name of the `OpenSpec` change to drive
        #[arg(long)]
        change: String,
        /// Maximum number of task slices to process
        #[arg(long, default_value = "10")]
        max_slices: u32,
    },
    /// Show loop status for a change
    Status {
        /// Name of the `OpenSpec` change to query
        #[arg(long)]
        change: String,
    },
    /// Cancel a running loop for a change
    Cancel {
        /// Name of the `OpenSpec` change to cancel
        #[arg(long)]
        change: String,
    },
}

#[derive(Subcommand)]
enum McpCmd {
    /// Register an MCP server
    Add {
        name: String,
        url: String,
        #[arg(long)]
        stdio: Option<String>,
    },
    /// List registered MCP servers
    List,
    /// Remove an MCP server by name
    Remove { name: String },
    /// Re-fetch tool lists from registered servers
    Refresh {
        /// Refresh a specific server only (omit for all)
        name: Option<String>,
    },
}

#[derive(Subcommand)]
enum SandboxCmd {
    /// Build the smedja-sandbox Docker image
    Build,
}

fn default_socket_path() -> PathBuf {
    let base = std::env::var("XDG_RUNTIME_DIR").unwrap_or_else(|_| "/tmp".into());
    PathBuf::from(base).join("smdjad.sock")
}

#[allow(clippy::too_many_lines)] // all CLI command arms live in one function per the spec
#[tokio::main]
async fn main() -> Result<()> {
    tracing_subscriber::fmt::init();
    let cli = Cli::parse();
    let sock = cli.sock.unwrap_or_else(default_socket_path);

    match cli.command {
        Cmd::Daemon { action } => match action {
            DaemonCmd::Status => cmd_daemon_status(&sock).await?,
            DaemonCmd::Start => cmd_daemon_start()?,
            _ => println!(
                "smj daemon {}: not yet implemented",
                match action {
                    DaemonCmd::Stop => "stop",
                    DaemonCmd::Restart => "restart",
                    _ => unreachable!(),
                }
            ),
        },
        Cmd::Skill { action } => {
            let registry = SkillRegistry::new(SkillRegistry::default_path());
            match action {
                SkillCmd::List => cmd_skill_list(&registry)?,
                SkillCmd::Install { path } => cmd_skill_install(&registry, &path)?,
                SkillCmd::Update { name, path } => cmd_skill_update(&registry, &name, &path)?,
                SkillCmd::Remove { name } => cmd_skill_remove(&registry, &name)?,
                SkillCmd::Sync { path } => cmd_skill_sync(&registry, &path)?,
            }
        }
        Cmd::Task { action } => {
            let mut client = Client::connect(&sock)
                .await
                .with_context(|| format!("smdjad not running ({})", sock.display()))?;
            match action {
                TaskCmd::List { status } => cmd_task_list(&mut client, status.as_deref()).await?,
                TaskCmd::Show { id } => cmd_task_show(&mut client, &id).await?,
                TaskCmd::Create { title, description } => {
                    cmd_task_create(&mut client, &title, description.as_deref()).await?;
                }
                TaskCmd::Close { id } => cmd_task_close(&mut client, &id).await?,
                TaskCmd::Parallel { goal, roles } => {
                    let resp = client
                        .call("task.parallel", json!({ "goal": goal, "roles": roles }))
                        .await
                        .context("task.parallel failed")?;
                    if let Some(tasks) = resp["tasks"].as_array() {
                        for t in tasks {
                            println!(
                                "{} ({})",
                                t["task_id"].as_str().unwrap_or("?"),
                                t["role"].as_str().unwrap_or("?"),
                            );
                        }
                    }
                }
                TaskCmd::Status { id } => {
                    let resp = client
                        .call("task.get", json!({ "id": id }))
                        .await
                        .context("task.get failed")?;
                    println!(
                        "{}",
                        serde_json::to_string_pretty(&resp).unwrap_or_default()
                    );
                }
                TaskCmd::Cancel { id } => {
                    client
                        .call("task.cancel", json!({ "task_id": id }))
                        .await
                        .context("task.cancel failed")?;
                    println!("cancelled: {id}");
                }
            }
        }
        Cmd::Session { action } => {
            if let SessionCmd::Blocks { id } = action {
                // ponytail: blocks are in-memory in the TUI; smj can only call the
                // smdjad RPC if one is wired, so for now print a message.
                println!(
                    "smj session blocks {id}: requires smdjad 'session.blocks' RPC (not yet wired)"
                );
            } else {
                let mut client = Client::connect(&sock)
                    .await
                    .with_context(|| format!("smdjad not running ({})", sock.display()))?;
                match action {
                    SessionCmd::List => cmd_session_list(&mut client).await?,
                    SessionCmd::Show { id } => cmd_session_show(&mut client, &id).await?,
                    SessionCmd::Rollback { id, turn } => {
                        cmd_session_rollback(&mut client, &id, turn).await?;
                    }
                    SessionCmd::Fork { id, .. } => {
                        println!("fork: not yet implemented for session {id}");
                    }
                    SessionCmd::Checkpoint { id } => {
                        let resp = client
                            .call("session.checkpoint.list", json!({ "session_id": id }))
                            .await
                            .context("session.checkpoint.list failed")?;
                        if let Some(arr) = resp.as_array() {
                            for cp in arr {
                                println!(
                                    "turn={} ts={} messages={}",
                                    cp["turn_n"].as_i64().unwrap_or(-1),
                                    cp["created_at"].as_f64().unwrap_or(0.0),
                                    cp["message_count"].as_u64().unwrap_or(0),
                                );
                            }
                        }
                    }
                    SessionCmd::Blocks { .. } => unreachable!(),
                    SessionCmd::Export { id } => {
                        let resp = client
                            .call("session.export", json!({ "id": id }))
                            .await
                            .context("session.export failed")?;
                        println!("{}", serde_json::to_string_pretty(&resp)?);
                    }
                }
            }
        }
        Cmd::Cost { session, .. } => {
            let mut client = Client::connect(&sock)
                .await
                .with_context(|| format!("smdjad not running ({})", sock.display()))?;
            let session_id = session.unwrap_or_default();
            if session_id.is_empty() {
                println!("smj cost: --session <session-id> required");
                return Ok(());
            }
            let resp = client
                .call("session.cost", json!({"session_id": session_id}))
                .await
                .context("session.cost failed")?;
            let usd = resp["total_usd"].as_f64().unwrap_or(0.0);
            println!("Session {session_id}: ${usd:.6}");
        }
        Cmd::Workspace { action } => match action {
            WorkspaceCmd::Agents {
                action: agents_action,
            } => match agents_action {
                AgentsCmd::Show => cmd_workspace_agents()?,
                AgentsCmd::Init => {
                    let target = std::path::Path::new(".smedja");
                    std::fs::create_dir_all(target)?;
                    let agents_toml = target.join("agents.toml");
                    if agents_toml.exists() {
                        anyhow::bail!(".smedja/agents.toml already exists");
                    }
                    std::fs::write(&agents_toml, AGENTS_TOML_TEMPLATE)?;
                    println!("Created {}", agents_toml.display());
                }
            },
            WorkspaceCmd::Index => println!("smj workspace index: not yet implemented"),
        },
        Cmd::Audit { .. } => {
            println!("smj audit: not yet implemented");
        }
        Cmd::Loop { action } => match action {
            LoopCmd::Run { change, max_slices } => {
                println!(
                    "smj loop run --change {change} --max-slices {max_slices}: not yet implemented"
                );
            }
            LoopCmd::Status { change } => {
                println!("smj loop status --change {change}: not yet implemented");
            }
            LoopCmd::Cancel { change } => {
                println!("smj loop cancel --change {change}: not yet implemented");
            }
        },
        Cmd::Sandbox { action } => match action {
            SandboxCmd::Build => {
                println!("Building smedja-sandbox:latest...");
                let status = std::process::Command::new("docker")
                    .args(["build", "-t", "smedja-sandbox:latest", "scripts/sandbox/"])
                    .status()
                    .map_err(|e| anyhow::anyhow!("docker not found: {e}"))?;
                if status.success() {
                    println!("Image built successfully.");
                } else {
                    anyhow::bail!("docker build failed");
                }
            }
        },
        Cmd::Mcp { action } => {
            let mut client = Client::connect(&sock)
                .await
                .with_context(|| format!("smdjad not running ({})", sock.display()))?;
            match action {
                McpCmd::Add { name, url, stdio } => {
                    let resp = client
                        .call(
                            "mcp.register",
                            json!({
                                "name": name,
                                "url": url,
                                "transport": if stdio.is_some() { "stdio" } else { "http" },
                                "tools_json": null,
                            }),
                        )
                        .await
                        .context("mcp.register failed")?;
                    println!("registered: {}", resp["name"].as_str().unwrap_or(&name));
                }
                McpCmd::List => {
                    let servers = client
                        .call("mcp.list", json!({}))
                        .await
                        .context("mcp.list failed")?;
                    if let Some(arr) = servers.as_array() {
                        for s in arr {
                            println!(
                                "{} {} ({})",
                                s["name"].as_str().unwrap_or("?"),
                                s["url"].as_str().unwrap_or(""),
                                s["transport"].as_str().unwrap_or("?"),
                            );
                        }
                    }
                }
                McpCmd::Remove { name } => {
                    client
                        .call("mcp.remove", json!({ "name": name }))
                        .await
                        .context("mcp.remove failed")?;
                    println!("removed: {name}");
                }
                McpCmd::Refresh { name } => {
                    // ponytail: refresh not yet wired in smdjad; print a stub message
                    match name {
                        Some(n) => println!("smj mcp refresh {n}: not yet implemented"),
                        None => println!("smj mcp refresh: not yet implemented"),
                    }
                }
            }
        }
        Cmd::Prices { action } => match action {
            PricesCmd::Update { file } => {
                if let Some(src) = file {
                    // ponytail: copy file to daemon config dir; daemon reloads on next request
                    let config_base = std::env::var("XDG_CONFIG_HOME").map_or_else(
                        |_| {
                            std::env::var("HOME").map_or_else(
                                |_| std::path::PathBuf::from(".config"),
                                |h| std::path::PathBuf::from(h).join(".config"),
                            )
                        },
                        std::path::PathBuf::from,
                    );
                    let dest = config_base.join("smedja").join("prices.toml");
                    std::fs::copy(&src, &dest)?;
                    println!("prices.toml updated \u{2192} {}", dest.display());
                } else {
                    // Print the embedded prices.toml location
                    println!("prices.toml is read from the daemon's config directory at startup");
                }
            }
        },
    }
    Ok(())
}

fn cmd_workspace_agents() -> Result<()> {
    use smedja_assayer::{Complexity, Role, Runner, Tier};

    let workspace_dir = std::env::current_dir().context("cannot determine working directory")?;
    let file_rules = smedja_assayer::load_rules(&workspace_dir).map_err(|e| anyhow::anyhow!(e))?;
    let mut assayer = smedja_assayer::Assayer::default_rules();
    assayer.prepend_rules(file_rules);

    println!("{:<15} {:<10} {:<8} MODEL", "ROLE", "RUNNER", "TIER");
    println!("{}", "-".repeat(55));

    for (role_name, role) in &[
        ("orchestrator", Role::Orchestrator),
        ("impl", Role::Impl),
        ("test", Role::Test),
        ("review", Role::Review),
        ("sre", Role::Sre),
    ] {
        let route = assayer.route(*role, Complexity::Coding);
        let runner = match route.runner {
            Runner::Claude => "claude",
            Runner::Local => "local",
            Runner::Codex => "codex",
            Runner::Copilot => "copilot",
        };
        let tier = match route.tier {
            Tier::Fast => "fast",
            Tier::Local => "local",
            Tier::Deep => "deep",
        };
        let model = route.model.as_deref().unwrap_or("-");
        println!("{role_name:<15} {runner:<10} {tier:<8} {model}");
    }
    Ok(())
}

async fn cmd_daemon_status(sock: &std::path::Path) -> Result<()> {
    match Client::connect(sock).await {
        Err(_) => {
            println!(
                "smdjad: not running (socket not found at {})",
                sock.display()
            );
            std::process::exit(1);
        }
        Ok(mut client) => {
            let resp = client
                .call("ping", serde_json::Value::Null)
                .await
                .with_context(|| "ping failed")?;
            println!("smdjad: running ({})", sock.display());
            println!("response: {resp}");
            Ok(())
        }
    }
}

fn cmd_daemon_start() -> Result<()> {
    // Locate smdjad relative to this binary.
    let exe = std::env::current_exe().context("cannot determine own path")?;
    let smdjad = exe
        .parent()
        .map(|p| p.join("smdjad"))
        .filter(|p| p.exists())
        .unwrap_or_else(|| PathBuf::from("smdjad"));

    std::process::Command::new(&smdjad)
        .stdin(std::process::Stdio::null())
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .spawn()
        .with_context(|| format!("failed to spawn {}", smdjad.display()))?;

    println!("smdjad started");
    Ok(())
}

fn cmd_skill_list(registry: &SkillRegistry) -> Result<()> {
    let skills = registry.scan()?;
    if skills.is_empty() {
        println!(
            "No skills installed at {}",
            SkillRegistry::default_path().display()
        );
        return Ok(());
    }
    println!("{:<30} {:<10} DESCRIPTION", "NAME", "VERSION");
    println!("{}", "-".repeat(80));
    for skill in &skills {
        let version = skill.manifest.version.as_deref().unwrap_or("-");
        let desc = skill
            .manifest
            .description
            .lines()
            .next()
            .unwrap_or("")
            .trim();
        println!("{:<30} {:<10} {}", skill.manifest.name, version, desc);
    }
    println!("\n{} skill(s) installed", skills.len());
    Ok(())
}

fn cmd_skill_install(registry: &SkillRegistry, path: &std::path::Path) -> Result<()> {
    let (name, content) = read_skill_file(path)?;
    registry
        .install(&name, &content)
        .with_context(|| format!("failed to install skill `{name}`"))?;
    println!("Installed skill `{name}`");
    Ok(())
}

fn cmd_skill_update(registry: &SkillRegistry, name: &str, path: &std::path::Path) -> Result<()> {
    let (_parsed_name, content) = read_skill_file(path)?;
    registry
        .update(name, &content)
        .with_context(|| format!("failed to update skill `{name}`"))?;
    println!("Updated skill `{name}`");
    Ok(())
}

fn cmd_skill_remove(registry: &SkillRegistry, name: &str) -> Result<()> {
    registry
        .remove(name)
        .with_context(|| format!("failed to remove skill `{name}`"))?;
    println!("Removed skill `{name}`");
    Ok(())
}

fn cmd_skill_sync(registry: &SkillRegistry, path: &std::path::Path) -> Result<()> {
    println!("Syncing from {} ...", path.display());
    let r = registry
        .sync_from(path)
        .with_context(|| format!("sync failed from {}", path.display()))?;
    for (name, reason) in &r.errors {
        println!("  error:   {name} — {reason}");
    }
    println!(
        "\n{} linked, {} updated, {} skipped, {} error(s)",
        r.linked,
        r.updated,
        r.skipped,
        r.errors.len()
    );
    Ok(())
}

async fn cmd_task_list(client: &mut Client, status: Option<&str>) -> Result<()> {
    let params = match status {
        Some(s) => serde_json::json!({"status": s}),
        None => serde_json::Value::Null,
    };
    let resp = client
        .call("task.list", params)
        .await
        .context("task.list failed")?;
    println!("{}", serde_json::to_string_pretty(&resp)?);
    Ok(())
}

async fn cmd_task_show(client: &mut Client, id: &str) -> Result<()> {
    let resp = client
        .call("task.get", serde_json::json!({"id": id}))
        .await
        .context("task.get failed")?;
    println!("{}", serde_json::to_string_pretty(&resp)?);
    Ok(())
}

async fn cmd_task_create(
    client: &mut Client,
    title: &str,
    description: Option<&str>,
) -> Result<()> {
    let params = serde_json::json!({
        "title": title,
        "description": description.unwrap_or(""),
    });
    let resp = client
        .call("task.create", params)
        .await
        .context("task.create failed")?;
    println!("Created task {}", resp["id"].as_str().unwrap_or("?"));
    Ok(())
}

async fn cmd_task_close(client: &mut Client, id: &str) -> Result<()> {
    client
        .call("task.close", serde_json::json!({"id": id}))
        .await
        .context("task.close failed")?;
    println!("Task {id} closed");
    Ok(())
}

async fn cmd_session_list(client: &mut Client) -> Result<()> {
    let resp = client
        .call("session.list", serde_json::Value::Null)
        .await
        .context("session.list failed")?;
    println!("{}", serde_json::to_string_pretty(&resp)?);
    Ok(())
}

async fn cmd_session_show(client: &mut Client, id: &str) -> Result<()> {
    let resp = client
        .call("session.get", json!({"id": id}))
        .await
        .context("session.get failed")?;
    println!("{}", serde_json::to_string_pretty(&resp)?);
    Ok(())
}

async fn cmd_session_rollback(client: &mut Client, session_id: &str, turn: u32) -> Result<()> {
    let resp = client
        .call(
            "session.rollback",
            json!({"session_id": session_id, "turn_n": turn}),
        )
        .await
        .context("session.rollback failed")?;
    println!(
        "Rolled back to turn {}: {}",
        turn,
        serde_json::to_string_pretty(&resp)?
    );
    Ok(())
}

/// Resolves a path to its SKILL.md content and the skill name from frontmatter.
fn read_skill_file(path: &std::path::Path) -> Result<(String, String)> {
    let skill_md = if path.is_dir() {
        path.join("SKILL.md")
    } else {
        path.to_owned()
    };
    let content = std::fs::read_to_string(&skill_md)
        .with_context(|| format!("cannot read {}", skill_md.display()))?;
    let skill = smedja_plugins::parse_skill(&content, &skill_md)
        .with_context(|| format!("invalid frontmatter in {}", skill_md.display()))?;
    Ok((skill.manifest.name, content))
}
